import{_ as t,a}from"./chunks/Material Dialog Dark.Tj9dEVeA.js";import{_ as i,o as s,c as o,al as r}from"./chunks/framework.-mVGFbqa.js";const k=JSON.parse('{"title":"👤 Material Dialog Page (Sensor View)","description":"","frontmatter":{},"headers":[],"relativePath":"dialogs/material-dialog-page.md","filePath":"dialogs/material-dialog-page.md"}'),n={name:"dialogs/material-dialog-page.md"};function l(d,e,p,h,c,g){return s(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="👤-material-dialog-page-sensor-view" tabindex="-1">👤 Material Dialog Page (Sensor View) <a class="header-anchor" href="#👤-material-dialog-page-sensor-view" aria-label="Permalink to &quot;👤 Material Dialog Page (Sensor View)&quot;">​</a></h1><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>🆕 Introduced in version 2.0.0</p></div><h3 id="✨-overview" tabindex="-1">✨ Overview <a class="header-anchor" href="#✨-overview" aria-label="Permalink to &quot;✨ Overview&quot;">​</a></h3><p>The <strong>Material Dialog</strong> is a new interactive component that allows you to view detailed information about a sensor device in a modern Material Design popup.<br> It provides contextual data, related entities, and device information, all inside a responsive dialog optimized for both desktop and mobile (with full-screen mode on phones).</p><p>This dialog gives users a fast and elegant way to check sensor states such as temperature, humidity, motion, or door status without leaving the main Lovelace dashboard.</p><div align="center"><table style="border-radius:28px;overflow:hidden;border-collapse:separate;border-spacing:0;max-width:1000px;"><tbody><tr><td width="50%" align="center" style="padding:24px;background:linear-gradient(135deg, #667eea 0%, #764ba2 100%);"><strong style="color:white;font-size:18px;">☀️ Light Mode</strong><br><br><img src="'+t+'" alt="Control Light" style="border-radius:20px;box-shadow:0 8px 32px rgba(0,0,0,0.2);"></td><td width="50%" align="center" style="padding:24px;background:linear-gradient(135deg, #2b5876 0%, #4e4376 100%);"><strong style="color:white;font-size:18px;">🌙 Dark Mode</strong><br><br><img src="'+a+`" alt="Control Dark" style="border-radius:20px;box-shadow:0 8px 32px rgba(0,0,0,0.4);"></td></tr></tbody></table></div><h2 id="✅-how-to-open-the-material-dialog" tabindex="-1">✅ How to Open the Material Dialog <a class="header-anchor" href="#✅-how-to-open-the-material-dialog" aria-label="Permalink to &quot;✅ How to Open the Material Dialog&quot;">​</a></h2><p>To open the Material Dialog, simply use the <code>material-button-card</code> with the attribute:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">use_default_toggle</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>When the button is configured with one of the supported sensor types, tapping it will automatically open the <strong>Material Dialog</strong> with detailed information.</p><p><strong>Example Configuration</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">custom:material-button-card</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">use_default_icon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">use_default_toggle</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">entity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">binary_sensor.motion_livingroom</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">control_type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">generic</span></span></code></pre></div><p>When the entity corresponds to a supported sensor (e.g., motion, door, temperature, humidity), the dialog will open automatically upon tap.</p><h2 id="⚙️-supported-device-classes" tabindex="-1">⚙️ Supported Device Classes <a class="header-anchor" href="#⚙️-supported-device-classes" aria-label="Permalink to &quot;⚙️ Supported Device Classes&quot;">​</a></h2><p>The <strong>Material Dialog</strong> is currently compatible with the following device types:</p><table tabindex="0"><thead><tr><th>Device Type</th><th>Description</th></tr></thead><tbody><tr><td><code>motion</code></td><td>Motion or presence sensors. Displays active/inactive state with animated feedback.</td></tr><tr><td><code>door</code></td><td>Door or window contact sensors. Shows open/closed status.</td></tr><tr><td><code>temperature</code></td><td>Temperature sensors. Displays current temperature and related entities.</td></tr><tr><td><code>humidity</code></td><td>Humidity sensors. Displays current humidity level and related information.</td></tr></tbody></table><blockquote><p>🧠 <em>More device classes may be added in future updates.</em></p></blockquote><h2 id="🎨-dialog-features" tabindex="-1">🎨 Dialog Features <a class="header-anchor" href="#🎨-dialog-features" aria-label="Permalink to &quot;🎨 Dialog Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Dynamic Header</strong></td><td>Shows device name, area, and state.</td></tr><tr><td><strong>Animated Status Circle</strong></td><td>Visual indicator (pulsing border) for active sensors.</td></tr><tr><td><strong>Related Entities Section</strong></td><td>Lists all entities associated with the same device (e.g., battery, signal strength).</td></tr><tr><td><strong>Action Menu</strong></td><td>Quick access to “Device Info” and “Related” pages.</td></tr><tr><td><strong>History Button</strong></td><td>Opens Home Assistant’s built-in history panel for the entity.</td></tr><tr><td><strong>Dark/Light Theme Support</strong></td><td>Automatically adapts to HA theme settings.</td></tr><tr><td><strong>Responsive Layout</strong></td><td>Fullscreen modal on mobile devices, centered dialog on desktop.</td></tr></tbody></table><h2 id="💡-example-use-cases" tabindex="-1">💡 Example Use Cases <a class="header-anchor" href="#💡-example-use-cases" aria-label="Permalink to &quot;💡 Example Use Cases&quot;">​</a></h2><ul><li>Tap a <strong>motion sensor</strong> → view detection status, last activity, and related entities.</li><li>Tap a <strong>temperature sensor</strong> → see the current temperature, humidity, and connected devices.</li><li>Tap a <strong>door sensor</strong> → quickly check if a window or door is open.</li></ul><h2 id="📱-mobile-experience" tabindex="-1">📱 Mobile Experience <a class="header-anchor" href="#📱-mobile-experience" aria-label="Permalink to &quot;📱 Mobile Experience&quot;">​</a></h2><p>On mobile devices (≤450px width), the dialog opens in <strong>fullscreen mode</strong> for a native app-like feel, with swipe-friendly navigation and easy closing gestures.</p><h2 id="⚠️-notes" tabindex="-1">⚠️ Notes <a class="header-anchor" href="#⚠️-notes" aria-label="Permalink to &quot;⚠️ Notes&quot;">​</a></h2><ul><li>The Material Dialog works only when <code>use_default_toggle: true</code> is enabled.</li><li>The dialog is automatically managed — no need to specify the type manually.</li><li>If the entity is not one of the supported sensor types, no dialog will open.</li></ul>`,25)])])}const b=i(n,[["render",l]]);export{k as __pageData,b as default};
